/**
 * Load the persistent power-ups enabled setting
 * @returns {boolean} True if persistent power-ups are enabled (default: true)
 */
export function loadPersistentPowerUpsEnabled() {
    const saved = localStorage.getItem("match2048_persistentPowerUpsEnabled");
    // Default to true if not set
    if (saved === null) {
        return true;
    }
    return saved === "true";
}

/**
 * Save the persistent power-ups enabled setting
 * @param {boolean} enabled - Whether persistent power-ups should be enabled
 */
export function savePersistentPowerUpsEnabled(enabled) {
    localStorage.setItem("match2048_persistentPowerUpsEnabled", enabled.toString());
}

export function loadSelectedPowerUps() {
    const saved = localStorage.getItem("match2048_selectedPowerUps");
    if (saved) {
        try {
            const parsed = JSON.parse(saved);
            if (Array.isArray(parsed) && parsed.length === 3) return parsed;
        } catch (e) {
            // fall through to default
        }
    }
    return ["hammer", "halve", "swap"];
}

export function saveSelectedPowerUps(selected) {
    localStorage.setItem("match2048_selectedPowerUps", JSON.stringify(selected));
}

/**
 * Load the "Super Streak Wildcard Teleport" setting.
 * When enabled and super streak is active, Wildcard rewards are replaced by Wildcard Teleport.
 * @returns {boolean} True if enabled (default: false)
 */
