                TILE_TYPE.BLOCKED,
                TILE_TYPE.BLOCKED_WITH_LIFE,
            ];
            if (!allowedTypes.includes(tile.type)) return;
            usePowerUpHammer(game, row, col, element);
            break;
        case "halve":
